118	        }),
119	      ).trim();
120	
121	  if (!password && !useEnvPassword) {
122	    return setIrcNickServ(params.cfg, params.accountId, {
123	      enabled: false,
124	      service,
125	    });
126	  }
127	
128	  const register = await params.prompter.confirm({
129	    message: "Send NickServ REGISTER on connect?",
130	    initialValue: existing?.register ?? false,
131	  });
132	  const registerEmail = register
133	    ? String(
134	        await params.prompter.text({
135	          message: "NickServ register email",
136	          initialValue:
137	            existing?.registerEmail ||
138	            (params.accountId === DEFAULT_ACCOUNT_ID
139	              ? process.env.IRC_NICKSERV_REGISTER_EMAIL
140	              : undefined),
141	          validate: (value) => (String(value ?? "").trim() ? undefined : "Required"),
142	        }),
143	      ).trim()
144	    : undefined;
145	
146	  return setIrcNickServ(params.cfg, params.accountId, {
147	    enabled: true,
148	    service,
149	    ...(password ? { password } : {}),
150	    register,
151	    ...(registerEmail ? { registerEmail } : {}),
152	  });
153	}
154	
155	const ircDmPolicy: ChannelSetupDmPolicy = {
156	  label: "IRC",
157	  channel,
158	  policyKey: "channels.irc.dmPolicy",
159	  allowFromKey: "channels.irc.allowFrom",
160	  getCurrent: (cfg) => (cfg as CoreConfig).channels?.irc?.dmPolicy ?? "pairing",
161	  setPolicy: (cfg, policy) => setIrcDmPolicy(cfg as CoreConfig, policy),
162	  promptAllowFrom: async ({ cfg, prompter, accountId }) =>
163	    await promptIrcAllowFrom({
164	      cfg: cfg as CoreConfig,
165	      prompter,
166	      accountId,
167	    }),
168	};
169	
170	export const ircSetupWizard: ChannelSetupWizard = {
171	  channel,
172	  status: createStandardChannelSetupStatus({
173	    channelLabel: "IRC",
174	    configuredLabel: "configured",
175	    unconfiguredLabel: "needs host + nick",
176	    configuredHint: "configured",
177	    unconfiguredHint: "needs host + nick",
178	    configuredScore: 1,
179	    unconfiguredScore: 0,
180	    includeStatusLine: true,
181	    resolveConfigured: ({ cfg }) =>
182	      listIrcAccountIds(cfg as CoreConfig).some(
183	        (accountId) => resolveIrcAccount({ cfg: cfg as CoreConfig, accountId }).configured,
184	      ),
185	  }),
186	  introNote: {
187	    title: "IRC setup",
188	    lines: [
189	      "IRC needs server host + bot nick.",
190	      "Recommended: TLS on port 6697.",
191	      "Optional: NickServ identify/register can be configured after the basic account fields.",
192	      'Set channels.irc.groupPolicy="allowlist" and channels.irc.groups for tighter channel control.',
193	      'Note: IRC channels are mention-gated by default. To allow unmentioned replies, set channels.irc.groups["#channel"].requireMention=false (or "*" for all).',
194	      "Env vars supported: IRC_HOST, IRC_PORT, IRC_TLS, IRC_NICK, IRC_USERNAME, IRC_REALNAME, IRC_PASSWORD, IRC_CHANNELS, IRC_NICKSERV_PASSWORD, IRC_NICKSERV_REGISTER_EMAIL.",
195	      `Docs: ${formatDocsLink("/channels/irc", "channels/irc")}`,
196	    ],
197	    shouldShow: ({ cfg, accountId }) =>
198	      !resolveIrcAccount({ cfg: cfg as CoreConfig, accountId }).configured,
199	  },
200	  prepare: async ({ cfg, accountId, credentialValues, prompter }) => {
201	    const resolved = resolveIrcAccount({ cfg: cfg as CoreConfig, accountId });
202	    const isDefaultAccount = accountId === DEFAULT_ACCOUNT_ID;
203	    const envHost = isDefaultAccount ? process.env.IRC_HOST?.trim() : "";
204	    const envNick = isDefaultAccount ? process.env.IRC_NICK?.trim() : "";
205	    const envReady = Boolean(envHost && envNick && !resolved.config.host && !resolved.config.nick);
206	
207	    if (envReady) {
208	      const useEnv = await prompter.confirm({
209	        message: "IRC_HOST and IRC_NICK detected. Use env vars?",
