233	        ...credentialValues,
234	        [USE_ENV_FLAG]: "0",
235	        [TLS_FLAG]: tls ? "1" : "0",
236	      },
237	    };
238	  },
239	  credentials: [],
240	  textInputs: [
241	    {
242	      inputKey: "httpHost",
243	      message: "IRC server host",
244	      currentValue: ({ cfg, accountId }) =>
245	        resolveIrcAccount({ cfg: cfg as CoreConfig, accountId }).config.host || undefined,
246	      shouldPrompt: ({ credentialValues }) => credentialValues[USE_ENV_FLAG] !== "1",
247	      validate: ({ value }) => (String(value ?? "").trim() ? undefined : "Required"),
248	      normalizeValue: ({ value }) => String(value).trim(),
249	      applySet: async ({ cfg, accountId, value }) =>
250	        updateIrcAccountConfig(cfg as CoreConfig, accountId, {
251	          enabled: true,
252	          host: value,
253	        }),
254	    },
255	    {
256	      inputKey: "httpPort",
257	      message: "IRC server port",
258	      currentValue: ({ cfg, accountId }) =>
