88	function resolveNickServConfig(accountId: string, nickserv?: IrcNickServConfig): IrcNickServConfig {
89	  const base = nickserv ?? {};
90	  const envPassword =
91	    accountId === DEFAULT_ACCOUNT_ID ? process.env.IRC_NICKSERV_PASSWORD?.trim() : undefined;
92	  const envRegisterEmail =
93	    accountId === DEFAULT_ACCOUNT_ID ? process.env.IRC_NICKSERV_REGISTER_EMAIL?.trim() : undefined;
94	
95	  const passwordFile = base.passwordFile?.trim();
96	  let resolvedPassword =
97	    normalizeResolvedSecretInputString({
98	      value: base.password,
99	      path: `channels.irc.accounts.${accountId}.nickserv.password`,
100	    }) ||
101	    envPassword ||
102	    "";
103	  if (!resolvedPassword && passwordFile) {
104	    resolvedPassword =
105	      tryReadSecretFileSync(passwordFile, "IRC NickServ password file", {
106	        rejectSymlink: true,
107	      }) ?? "";
108	  }
109	
110	  const merged: IrcNickServConfig = {
111	    ...base,
112	    service: base.service?.trim() || undefined,
113	    passwordFile: passwordFile || undefined,
114	    password: resolvedPassword || undefined,
115	    registerEmail: base.registerEmail?.trim() || envRegisterEmail || undefined,
116	  };
117	  return merged;
118	}
