11	
12	export type IrcMonitorOptions = {
13	  accountId?: string;
14	  config?: CoreConfig;
15	  runtime?: RuntimeEnv;
16	  abortSignal?: AbortSignal;
17	  statusSink?: (patch: { lastInboundAt?: number; lastOutboundAt?: number }) => void;
18	  onMessage?: (message: IrcInboundMessage, client: IrcClient) => void | Promise<void>;
19	};
20	
21	export function resolveIrcInboundTarget(params: { target: string; senderNick: string }): {
22	  isGroup: boolean;
23	  target: string;
24	  rawTarget: string;
25	} {
26	  const rawTarget = params.target;
27	  const isGroup = isChannelTarget(rawTarget);
28	  if (isGroup) {
29	    return { isGroup: true, target: rawTarget, rawTarget };
30	  }
31	  const senderNick = params.senderNick.trim();
32	  return { isGroup: false, target: senderNick || rawTarget, rawTarget };
33	}
34	
35	export async function monitorIrcProvider(opts: IrcMonitorOptions): Promise<{ stop: () => void }> {
36	  const core = getIrcRuntime();
37	  const cfg = opts.config ?? (core.config.loadConfig() as CoreConfig);
38	  const account = resolveIrcAccount({
39	    cfg,
40	    accountId: opts.accountId,
41	  });
42	
43	  const runtime: RuntimeEnv = resolveLoggerBackedRuntime(
44	    opts.runtime,
45	    core.logging.getChildLogger(),
46	  );
47	
48	  if (!account.configured) {
49	    throw new Error(
50	      `IRC is not configured for account "${account.accountId}" (need host and nick in channels.irc).`,
51	    );
52	  }
53	
54	  const logger = core.logging.getChildLogger({
55	    channel: "irc",
56	    accountId: account.accountId,
57	  });
58	
59	  let client: IrcClient | null = null;
60	
61	  client = await connectIrcClient(
62	    buildIrcConnectOptions(account, {
63	      channels: account.config.channels,
64	      abortSignal: opts.abortSignal,
65	      onLine: (line) => {
66	        if (core.logging.shouldLogVerbose()) {
67	          logger.debug?.(`[${account.accountId}] << ${line}`);
68	        }
69	      },
70	      onNotice: (text, target) => {
71	        if (core.logging.shouldLogVerbose()) {
72	          logger.debug?.(`[${account.accountId}] notice ${target ?? ""}: ${text}`);
73	        }
74	      },
75	      onError: (error) => {
76	        logger.error(`[${account.accountId}] IRC error: ${error.message}`);
77	      },
78	      onPrivmsg: async (event) => {
79	        if (!client) {
80	          return;
81	        }
82	        if (event.senderNick.toLowerCase() === client.nick.toLowerCase()) {
83	          return;
84	        }
85	
86	        const inboundTarget = resolveIrcInboundTarget({
87	          target: event.target,
88	          senderNick: event.senderNick,
89	        });
90	        const message: IrcInboundMessage = {
91	          messageId: makeIrcMessageId(),
92	          target: inboundTarget.target,
93	          rawTarget: inboundTarget.rawTarget,
94	          senderNick: event.senderNick,
95	          senderUser: event.senderUser,
96	          senderHost: event.senderHost,
97	          text: event.text,
98	          timestamp: Date.now(),
99	          isGroup: inboundTarget.isGroup,
100	        };
101	
102	        core.channel.activity.record({
103	          channel: "irc",
104	          accountId: account.accountId,
105	          direction: "inbound",
106	          at: message.timestamp,
107	        });
108	
109	        if (opts.onMessage) {
110	          await opts.onMessage(message, client);
111	          return;
112	        }
113	
114	        await handleIrcInbound({
115	          message,
116	          account,
117	          config: cfg,
118	          runtime,
119	          connectedNick: client.nick,
120	          sendReply: async (target, text) => {
121	            client?.sendPrivmsg(target, text);
122	            opts.statusSink?.({ lastOutboundAt: Date.now() });
123	            core.channel.activity.record({
124	              channel: "irc",
125	              accountId: account.accountId,
126	              direction: "outbound",
127	            });
128	          },
129	          statusSink: opts.statusSink,
130	        });
131	      },
132	    }),
133	  );
134	
135	  logger.info(
136	    `[${account.accountId}] connected to ${account.host}:${account.port}${account.tls ? " (tls)" : ""} as ${client.nick}`,
137	  );
138	
139	  return {
140	    stop: () => {
141	      client?.quit("shutdown");
142	      client = null;
143	    },
144	  };
145	}
