14	function resolveSynologyChatInboundRoute(params: {
15	  cfg: OpenClawConfig;
16	  account: ResolvedSynologyChatAccount;
17	  userId: string;
18	}) {
19	  const rt = getSynologyRuntime();
20	  const route = rt.channel.routing.resolveAgentRoute({
21	    cfg: params.cfg,
22	    channel: CHANNEL_ID,
23	    accountId: params.account.accountId,
24	    peer: {
25	      kind: "direct",
26	      id: params.userId,
27	    },
28	  });
29	  return {
30	    rt,
31	    route,
32	    sessionKey: buildSynologyChatInboundSessionKey({
33	      agentId: route.agentId,
34	      accountId: params.account.accountId,
35	      userId: params.userId,
36	      identityLinks: params.cfg.session?.identityLinks,
37	    }),
38	  };
39	}
