58	export async function dispatchSynologyChatInboundTurn(params: {
59	  account: ResolvedSynologyChatAccount;
60	  msg: SynologyInboundMessage;
61	  log?: SynologyChannelLog;
62	}): Promise<null> {
63	  const rt = getSynologyRuntime();
64	  const currentCfg = await rt.config.loadConfig();
65	
66	  // The Chat API user_id (for sending) may differ from the webhook
67	  // user_id (used for sessions/pairing). Use chatUserId for API calls.
68	  const sendUserId = params.msg.chatUserId ?? params.msg.from;
69	  const resolved = resolveSynologyChatInboundRoute({
70	    cfg: currentCfg,
71	    account: params.account,
72	    userId: params.msg.from,
73	  });
74	  const msgCtx = buildSynologyChatInboundContext({
75	    finalizeInboundContext: resolved.rt.channel.reply.finalizeInboundContext,
76	    account: params.account,
77	    msg: params.msg,
78	    sessionKey: resolved.sessionKey,
79	  });
80	
81	  await resolved.rt.channel.reply.dispatchReplyWithBufferedBlockDispatcher({
82	    ctx: msgCtx,
83	    cfg: currentCfg,
84	    dispatcherOptions: {
85	      deliver: async (payload: { text?: string; body?: string }) => {
86	        await deliverSynologyChatReply({
87	          account: params.account,
88	          sendUserId,
89	          payload,
90	        });
91	      },
92	      onReplyStart: () => {
93	        params.log?.info?.(`Agent reply started for ${params.msg.from}`);
94	      },
95	    },
96	  });
97	
98	  return null;
99	}
