28	/** Adapt a simple logger into the RuntimeEnv contract used by shared plugin SDK helpers. */
29	export function createLoggerBackedRuntime(params: {
30	  logger: LoggerLike;
31	  exitError?: (code: number) => Error;
32	}): OutputRuntimeEnv {
33	  return {
34	    log: (...args) => {
35	      params.logger.info(format(...args));
36	    },
37	    error: (...args) => {
38	      params.logger.error(format(...args));
39	    },
40	    writeStdout: (value) => {
41	      params.logger.info(value);
42	    },
43	    writeJson: (value, space = 2) => {
44	      params.logger.info(JSON.stringify(value, null, space > 0 ? space : undefined));
45	    },
46	    exit: (code: number): never => {
47	      throw params.exitError?.(code) ?? new Error(`exit ${code}`);
48	    },
49	  };
50	}
