265	function formatAllowEntry(entry: string): string {
266	  const trimmed = entry.trim();
267	  if (!trimmed) {
268	    return "";
269	  }
270	  if (trimmed.startsWith("@")) {
271	    const username = trimmed.slice(1).trim();
272	    return username ? `@${username.toLowerCase()}` : "";
273	  }
274	  return trimmed.replace(/^(mattermost|user):/i, "").toLowerCase();
275	}
