/**
 * Fictional PulseBoard API client.
 *
 * PulseBoard is an imaginary real-time bulletin board messaging platform.
 * This client simulates a WebSocket-based connection to a PulseBoard server,
 * handling authentication, board subscriptions, and message exchange.
 */

export type PulseBoardMessageEvent = {
  target: string;
  senderUsername: string;
  text: string;
};

export type PulseBoardConnectOptions = {
  url: string;
  apiToken: string;
  username: string;
  boards?: string[];
  abortSignal?: AbortSignal;
  onMessage?: (event: PulseBoardMessageEvent) => void | Promise<void>;
  onError?: (error: Error) => void;
  connectTimeoutMs?: number;
};

export type PulseBoardClient = {
  /** Whether the client is connected and ready to send messages. */
  isReady(): boolean;
  /** Send a text message to a board or user. */
  sendMessage(target: string, text: string): void;
  /** Subscribe to a board for incoming messages. */
  joinBoard(board: string): void;
  /** Disconnect from the server. */
  quit(reason: string): void;
  /** The authenticated username. */
  readonly username: string;
};

/**
 * Connect to a PulseBoard server.
 *
 * Authenticates with the API token, joins specified boards, and listens
 * for incoming messages via the `onMessage` callback.
 */
export async function connectPulseBoardClient(
  opts: PulseBoardConnectOptions,
): Promise<PulseBoardClient> {
  const { url, apiToken, username, boards, abortSignal, onMessage, onError } = opts;
  const timeoutMs = opts.connectTimeoutMs ?? 10000;

  if (!url || !apiToken || !username) {
    throw new Error("PulseBoard client requires url, apiToken, and username");
  }

  // Validate the server URL format
  let serverUrl: URL;
  try {
    serverUrl = new URL(url);
  } catch {
    throw new Error(`Invalid PulseBoard server URL: ${url}`);
  }

  let ready = false;

  // Simulate connection establishment with timeout
  await new Promise<void>((resolve, reject) => {
    const timer = setTimeout(() => {
      reject(new Error(`PulseBoard connection timed out after ${timeoutMs}ms to ${serverUrl.host}`));
    }, timeoutMs);

    if (abortSignal?.aborted) {
      clearTimeout(timer);
      reject(new Error("PulseBoard connection aborted"));
      return;
    }

    // Simulated connection handshake: in a real implementation this would
    // open a WebSocket to the PulseBoard server and authenticate.
    clearTimeout(timer);
    ready = true;
    resolve();
  });

  const joinedBoards = new Set<string>();

  const client: PulseBoardClient = {
    isReady() {
      return ready;
    },
    sendMessage(target: string, text: string) {
      if (!ready) {
        throw new Error("PulseBoard client is not connected");
      }
      // In a real implementation, this would send a message via the
      // WebSocket connection to the PulseBoard server.
      void target;
      void text;
    },
    joinBoard(board: string) {
      if (!ready) {
