import type { PulseBoardGroupConfig, PulseBoardInboundMessage } from "./types.js";
import {
  normalizePulseBoardAllowlist,
  resolvePulseBoardAllowlistMatch,
} from "./normalize.js";

export type PulseBoardGroupMatch = {
  /** Matched group config (exact board name match). */
  groupConfig?: PulseBoardGroupConfig;
  /** Wildcard config (from "*" entry). */
  wildcardConfig?: PulseBoardGroupConfig;
};

/**
 * Match a target board against configured groups entries.
 * Supports exact board name match and wildcard "*".
 */
export function resolvePulseBoardGroupMatch(params: {
  groups?: Record<string, PulseBoardGroupConfig>;
  target: string;
}): PulseBoardGroupMatch {
  const { groups, target } = params;
  if (!groups) {
    return {};
  }
  const normalizedTarget = target.trim().toLowerCase();
  let groupConfig: PulseBoardGroupConfig | undefined;
  let wildcardConfig: PulseBoardGroupConfig | undefined;

  for (const [key, config] of Object.entries(groups)) {
    if (!config) {
      continue;
    }
    if (key === "*") {
      wildcardConfig = config;
    } else if (key.trim().toLowerCase() === normalizedTarget) {
      groupConfig = config;
    }
  }
  return { groupConfig, wildcardConfig };
}

/**
 * Check if a board message should be allowed based on group policy.
 */
export function resolvePulseBoardGroupAccessGate(params: {
  groupPolicy: string;
  groupMatch: PulseBoardGroupMatch;
}): { allowed: boolean; reason?: string } {
  const { groupPolicy, groupMatch } = params;
  if (groupPolicy === "disabled") {
    return { allowed: false, reason: "groupPolicy=disabled" };
  }
  if (groupPolicy === "open") {
    return { allowed: true };
  }
  // allowlist: require explicit board entry or wildcard
  if (groupMatch.groupConfig || groupMatch.wildcardConfig) {
    return { allowed: true };
  }
  return { allowed: false, reason: "board not in allowlist" };
}

/**
 * Resolve whether @mention is required for a board.
 * Defaults to true (mention required) when not explicitly set.
 */
export function resolvePulseBoardRequireMention(params: {
  groupConfig?: PulseBoardGroupConfig;
  wildcardConfig?: PulseBoardGroupConfig;
}): boolean {
  if (params.groupConfig?.requireMention !== undefined) {
    return params.groupConfig.requireMention;
  }
  if (params.wildcardConfig?.requireMention !== undefined) {
    return params.wildcardConfig.requireMention;
  }
  return true;
}

/**
 * Check if a message should be dropped due to mention gating.
 */
export function resolvePulseBoardMentionGate(params: {
  isGroup: boolean;
  requireMention: boolean;
  wasMentioned: boolean;
  hasControlCommand: boolean;
  allowTextCommands: boolean;
  commandAuthorized: boolean;
}): { shouldSkip: boolean; reason?: string } {
  if (!params.isGroup) {
    return { shouldSkip: false };
  }
  if (!params.requireMention) {
    return { shouldSkip: false };
  }
  if (params.wasMentioned) {
    return { shouldSkip: false };
  }
  // Allow authorized control commands even without mention
  if (params.hasControlCommand && params.allowTextCommands && params.commandAuthorized) {
    return { shouldSkip: false };
  }
  return { shouldSkip: true, reason: "mention required" };
}

/**
 * Check if a sender is allowed in a board based on allowlists.
 */
export function resolvePulseBoardGroupSenderAllowed(params: {
  groupPolicy: string;
  message: PulseBoardInboundMessage;
  outerAllowFrom: string[];
  innerAllowFrom: string[];
}): boolean {
  if (params.groupPolicy === "open") {
    return true;
  }
  // Check inner (per-board) allowlist first
  if (params.innerAllowFrom.length > 0) {
    return resolvePulseBoardAllowlistMatch({
      allowFrom: params.innerAllowFrom,
      message: params.message,
    }).allowed;
  }
  // Fall back to outer (channel-level) group allowlist
  if (params.outerAllowFrom.length > 0) {
    return resolvePulseBoardAllowlistMatch({
      allowFrom: params.outerAllowFrom,
      message: params.message,
    }).allowed;
  }
  // No allowlist configured: allow (board access already gated)
  return true;
}

